            ->where('status', 'verified')
            ->latest('verified_at')
            ->paginate(15);

        // Pending amount
        $pendingAmount = PaymentRequest::where('status', 'pending')->sum('amount');

        return view('admin.finance.index', compact(
            'totalRevenue', 'monthlyRevenue', 'yearlyRevenue',
            'monthlyData', 'transactions', 'pendingAmount'
        ));
    }
}
```

